var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"본부와의 통신은 아직인가요, 리브 경?","JPN":"本部との通信はまだですか、リブ卿？","ENG":"Still no word from HQ, Dame Liv?","TWN":"還沒有和總部取得聯絡嗎，莉芙？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"응. 침식파의 영향인지 통신기가 완전 맛이 가버렸네.","JPN":"うん。侵食波の影響か、通信機が完全に壊れちゃってるみたい。","ENG":"Nope. I think the Corruption ray fried the transmitter. Totally busted.","TWN":"嗯。可能是受到侵蝕波的影響，通訊器完全壞掉了。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스. 이거 네 능력으로는 못 고쳐?","JPN":"アリウスの力で修理できない？","ENG":"Arius, can't you fix it with your powers?","TWN":"埃里奧斯。這個你用你的能力修不好嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"리브 언니… 제 능력으로 기계는 못 고쳐요.","JPN":"リブさん……私の能力で機械は直せません。","ENG":"Sorry, Liv... My powers don't work on machines.","TWN":"莉芙姊姊…我的能力無法修理機械。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어, 그래? 난 왜 기계한테도 되는 줄 알았지?","JPN":"え、そうなの？　機械にも効くのかと思ってた。","ENG":"Huh, really? I thought they worked on machines too for some reason.","TWN":"喔，是嗎？我還以為對機器也有效呢？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"금방 풀어지는 건 리브 경의 나쁜 버릇입니다. 사태가 갑작스러웠으니, 저희는 어디서 나타날지 모르는 침식체를 꾸준히 경계해야 해요.","JPN":"すぐ緊張を解くのはリブ卿の悪い癖です。状況が急変した以上、どこから侵食体が現れるかわからないので警戒を怠らないことです。","ENG":"Your mood shifts far too easily, Dame Liv. With things so unpredictable, we must stay alert for any C.O.s that might appear.","TWN":"輕易放鬆警惕是莉芙的壞習慣。事態突如其來，我們必須時刻警惕那些隨時可能出現的侵蝕體。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저희 로웰 가의 고조부께서도 말씀하셨죠. 자고로 평화와 위기는 동전의 앞 뒷면과 같고, 이를 대비하는 것이 기사단의 덕목이다. 조금 설명 드리자면 고조부님께서 오베르뉴에 계시던 시절부터 시작해야 하는데-.","JPN":"我がローウェル家の高祖父も言っていました。古くから平和と危機は表裏一体であり、それに備えることこそが騎士団の嗜みである、と。この話をするには、高祖父がオーヴェルニュにいた頃から話す必要があるのですが……。","ENG":"As my great-great-grandfather from House Lowell used to say, \\"Peace and crisis are two sides of the same coin, and preparing for both is a knight's duty.\\" Now, to explain that, we must begin from the time he served in Auvergne–","TWN":"我們勞威爾家的高祖也曾說過，所謂和平與危機就像硬幣的兩面，而做好準備是騎士團的美德。簡單來說，要從高祖在奧弗涅的時代開始講起——。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아악-! 그 놈의 고조부! 그리고 통신 좀 안 될 수도 있지 뭘 그리 들들 볶아?","JPN":"ああもう！　その高祖父の話、もういいって！　それに通信が繋がらないくらいで大騒ぎしすぎ！","ENG":"Aagh, not the great-great-grandpa speech again! So what if the comms are down? Stop harping on it!","TWN":"啊啊-！ 那個傢伙的曾祖父！ 通訊有時候不通也是正常的，為什麼要這麼煩人呢?"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경을 도우려는 건 아니지만, 해당 발언에는 저도 동의합니다, 부단장님.","JPN":"リブ卿の肩を持つつもりはありませんが、その点については私も同意見です、副団長。","ENG":"I'm not trying to side with Dame Liv, but I do agree with her this time, Deputy.","TWN":"雖然我並不是想幫莉芙，但我同意她的說法，副團長。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"갑작스러운 침식사태에 대항하기 위해 태스크포스들이 각 지부 중심으로 배치된 상황에서.","JPN":"急な侵食事態への対処で、タスクフォースが各支部を中心に配置されている現状を考えると……","ENG":"Given the sudden Corruption disaster, all TASKFORCEs have been deployed to the center of each branch.","TWN":"為了應對突如其來的侵蝕事件，各特遣勢力已在各分部中心部署。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"주요 병력이 자리를 비웠다고는 하나, 본부가 위험에 처할 확률은 현저히 낮아요.","JPN":"主要兵力が不在とはいえ、本部が危機に陥る確率はかなり低い。","ENG":"Even if HQ is short on main forces, the odds of it being in actual danger are slim.","TWN":"雖然主要兵力已經撤離，但總部遭遇危險的機率仍然很低。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"양방향 통신에 문제가 있는 것도 리브 경의 말 대로 침식파의 영향일 겁니다.","JPN":"双方向の通信に不具合が出ているのも、リブ卿の言う通り侵食波の影響だと思います。","ENG":"And like Liv said, the transmission issues are probably just due to the Corruption ray.","TWN":"雙向通訊出現問題也可能是受到侵蝕波的影響，正如莉芙所說。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그래! 우리가 뭐 한 달 동안 나가 있던 것도 아닌데, 뭐가 그리 걱정이야?","JPN":"そう！　たかが数日外に出てただけなのに大げさだよ！","ENG":"Exactly! It's not like we've been gone for a whole month. What's there to worry about?","TWN":"對啊！我們又不是出去一個月，擔心什麼呢？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"Still...","TWN":"那個……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"피오네 경. 잠깐 괜찮을까요?","JPN":"フィオネ卿、少しよろしいですか？","ENG":"Dame Fione. Have a moment?","TWN":"菲奧尼，能打擾你一下嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"메데이아 경? 다행이군요. 본부와 통신이 닿지 않아 걱정하던 참이었습니다.","JPN":"メデイア卿？　ご無事でよかったです。本部と連絡がつかず、心配していました。","ENG":"Dame Medea? I'm glad to hear from you. We were worried since we couldn't get through to HQ.","TWN":"美狄亞？太好了。我正擔心無法與總部取得聯絡。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"본부에 별다른 이상이 없다면, 다른 방어선에 지원을 가는 것도 고려해볼 수 있겠군요.","JPN":"本部に異常がないのなら、他の防御線への支援も検討できそうですね。","ENG":"If everything's fine on HQ, we might consider sending reinforcements to another defense line.","TWN":"如果總部沒有特別異常的話，也可以考慮去支援其他防線。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……역시, 그쪽에서도 본부와 연락이 닿지 않는 건 매한가지였군요.","JPN":"……やはり、そちらでも本部とは連絡が取れなかったようですね。","ENG":"...So it's the same for you. HQ isn't responding on your side either.","TWN":"……果然，那邊也一樣聯絡不上總部啊。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"무슨 말씀이시죠? 메데이아 경은 본부에 계신 게 아니었습니까?","JPN":"どういうことですか？　メデイア卿は本部にいらしたのでは？","ENG":"Wait, what? Weren't you stationed at HQ?","TWN":"你在說什麼呢？美狄亞不是在總部嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"얼마 전까진 그랬죠. 로터스 지부 쪽에 문제가 하나 생겼었거든요.","JPN":"少し前までは、そうでした。ロータス支部の方で問題が発生していまして。","ENG":"I was, until recently. Something came up over at the Lotus branch.","TWN":"直到不久前都是這樣。洛德斯分部那邊出了點問題。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"확인 결과, 레온하르트 경이 이번 이상 침식현상을 일으킨 범인의 추격 중에 있다고 합니다만…….","JPN":"確認した結果、レオンハルト卿が今回の異常侵食現象を引き起こした犯人を追っているとのことですが……","ENG":"It turns out Dame Leonhardt is tracking the individual responsible for this abnormal Counterside Effect...","TWN":"確認結果，里恩哈特正在追蹤此次異常侵蝕現象的罪犯……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"로터스 지부와의 통신이 재개된 후 검토한 바에 의하면, 전달된 정보와 일부 차이가 있었습니다.","JPN":"ロータス支部との通信が復旧してから再確認したところ、伝えられた情報の一部に齟齬がありました。","ENG":"But after communications with Lotus were reestablished, some of the details didn't add up.","TWN":"在與洛德斯分部重新建立通訊後，經審查發現傳遞的資訊與部分內容存在差異。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단에 잘못된 정보가 전달되었다는 겁니까?","JPN":"騎士団に誤った情報が伝達されていたということですか？","ENG":"You mean the Order received false intel?","TWN":"騎士團收到錯誤的資訊了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……설마!","JPN":"……まさか！","ENG":"...It can't be!","TWN":"……難道？！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"단원들 사이에서 정보 교환이 안 되었을 가능성이 있으니 확단하기는 이릅니다.","JPN":"団員同士の情報共有が不十分だった可能性もあるので、断定はできません。","ENG":"Let's not jump to conclusions. It could've just been a breakdown in communication between members.","TWN":"由於可能在成員之間沒有進行資訊交換，所以現在下結論還為時過早。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만… 가능하다면 빠르게 본부에 복귀해주세요.","JPN":"ですが……可能であれば、早急に本部へ戻ってください。","ENG":"But... if possible, return to HQ immediately.","TWN":"但是……如果可能的話，請儘快返回總部。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};